'use client'

import { Button } from '@/components/ui/button'
import { ArrowUpRight } from 'lucide-react'
import Image from 'next/image'

interface VehicleTypeCardProps {
  type: string
  image: string
  icon: React.ReactNode
  gridClass?: string
  onTypeClick?: (type: string) => void
}

interface BrowseByTypeProps {
  onViewAll?: () => void
  onTypeClick?: (type: string) => void
}

function VehicleTypeCard({ type, image, icon, gridClass = '', onTypeClick }: VehicleTypeCardProps) {
  const handleClick = () => {
    onTypeClick?.(type)
  }

  return (
    <div 
      className={`${gridClass} relative rounded-2xl overflow-hidden group cursor-pointer`}
      onClick={handleClick}
    >
      <Image
        src={image}
        alt={type}
        fill
        className="object-cover transition-transform group-hover:scale-105"
        sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
        loading="lazy"
      />
      <div className="absolute bottom-6 left-6">
        <div className="bg-white rounded-[44px] px-6 py-3 flex items-center gap-3 shadow-sm">
          {icon}
          <span className="text-[#050B20] text-[15px] font-medium">{type}</span>
        </div>
      </div>
    </div>
  )
}

